from collections import defaultdict, Counter
import math


class NgramLM:
    """Simple n-gram language model with add-k (Laplace) smoothing."""

    def __init__(self, n: int = 3, k: float = 0.1):
        self.n = n
        self.k = k          # smoothing constant
        self.counts = defaultdict(Counter)   # context -> {next_token: count}
        self.vocab = set()

    def train(self, tokens: list):
        self.vocab.update(tokens)
        V = len(self.vocab)
        # Count n-grams
        for i in range(len(tokens) - self.n + 1):
            ctx = tuple(tokens[i:i + self.n - 1])   # context
            nxt = tokens[i + self.n - 1]             # next token
            self.counts[ctx][nxt] += 1

    def log_prob(self, context: tuple, token: str) -> float:
        """log p(token | context) with Laplace smoothing."""
        ctx = tuple(context[-(self.n - 1):])   # trim to n-1
        count_nxt = self.counts[ctx].get(token, 0) + self.k
        total = sum(self.counts[ctx].values()) + self.k * len(self.vocab)
        return math.log(count_nxt / total)

    def perplexity(self, tokens: list) -> float:
        """Compute perplexity on a token sequence."""
        log_prob_sum = 0.0
        T = len(tokens) - self.n + 1
        for i in range(T):
            ctx = tuple(tokens[i:i + self.n - 1])
            log_prob_sum += self.log_prob(ctx, tokens[i + self.n - 1])
        return math.exp(-log_prob_sum / T)
